<div class="de">
<svg viewBox="0 0 700 460" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="28" fill="#fafafa" font-size="15" font-weight="700" font-family="sans-serif">Zeitverlauf nach einem Whale-Transfer: echtes vs. falsches Signal</text>
  <text x="20" y="48" fill="#71717a" font-size="13" font-family="sans-serif">Der Moby-Dick-Effekt (oben) vs. das Problem der Fehlzuschreibung durch Börsen-Aufräumarbeit (unten) · Konzeptdiagramm</text>
  <text x="20" y="76" fill="#a1a1aa" font-size="13" font-weight="700" font-family="sans-serif">① Der Moby-Dick-Effekt — statistische Signifikanz nach verstrichener Zeit</text>
  <line x1="60" y1="170" x2="640" y2="170" stroke="#3f3f46" stroke-width="1.5"/>
  <rect x="110" y="140" width="90" height="30" rx="4" fill="#3f3f46"/>
  <text x="155" y="160" fill="#d4d4d8" font-size="13" text-anchor="middle" font-family="sans-serif">1 Stunde</text>
  <text x="155" y="188" fill="#71717a" font-size="12" text-anchor="middle" font-family="sans-serif">fast keine signifikante Reaktion</text>
  <rect x="300" y="105" width="90" height="65" rx="4" fill="#fbbf24"/>
  <text x="345" y="160" fill="#111113" font-size="13" font-weight="700" text-anchor="middle" font-family="sans-serif">6 Stunden</text>
  <text x="345" y="188" fill="#fbbf24" font-size="12" text-anchor="middle" font-family="sans-serif">statistisch signifikant</text>
  <rect x="490" y="90" width="90" height="80" rx="4" fill="#fbbf24"/>
  <text x="535" y="160" fill="#111113" font-size="13" font-weight="700" text-anchor="middle" font-family="sans-serif">24 Stunden</text>
  <text x="535" y="188" fill="#fbbf24" font-size="12" text-anchor="middle" font-family="sans-serif">statistisch signifikant</text>
  <text x="20" y="238" fill="#a1a1aa" font-size="13" font-weight="700" font-family="sans-serif">② Aber wer ist dieser "Wal" wirklich? — das Problem der Signalquellen-Fehlzuschreibung</text>
  <rect x="60" y="260" width="580" height="150" rx="8" fill="none" stroke="#3f3f46" stroke-width="1.5" stroke-dasharray="4,4"/>
  <text x="350" y="285" fill="#71717a" font-size="12" text-anchor="middle" font-family="sans-serif">Ein Signal — "Anstieg des großen Wallet-Guthabens" — mit nicht unterscheidbaren Ursachen</text>
  <rect x="90" y="305" width="230" height="80" rx="6" fill="#f87171" opacity="0.15"/>
  <text x="205" y="335" fill="#f87171" font-size="13" font-weight="700" text-anchor="middle" font-family="sans-serif">Interne Börsen-Umschichtung</text>
  <text x="205" y="358" fill="#a1a1aa" font-size="12" text-anchor="middle" font-family="sans-serif">Sicherheits-/Betriebsverlagerung</text>
  <text x="205" y="376" fill="#a1a1aa" font-size="12" text-anchor="middle" font-family="sans-serif">kein Informationswert</text>
